CustomField.formula:
IF(
   (RecordType.DeveloperName = 'Informatics'
  && eq_Is_Eloqua_Lead__c = true
   )
, IF(   (TEXT(eq_Default_MQL__c)= 'true' 
	  || TEXT(eq_Contact_Requested__c)= 'true'
	  || TEXT(eq_Quote_Requested__c)= 'true'
	  || TEXT(Buying_Horizon__c)= '0-3 Months'
	  || TEXT(Buying_Horizon__c)= '3-6 Months'
		)
	  , 'A - Sales Ready/MQL'

	  , IF(
		  (
			  (TEXT(eq_Default_MQL__c)= 'false'
			|| TEXT(eq_Default_MQL__c)= 'Unknown'
			|| TEXT(eq_Default_MQL__c)= ''
			   ) 
		   && (TEXT(eq_Contact_Requested__c)= 'false'
			|| TEXT(eq_Contact_Requested__c)= 'Unknown' 
			|| TEXT(eq_Contact_Requested__c)= ''
			   ) 
		   && (TEXT(eq_Quote_Requested__c)= 'false'
			|| TEXT(eq_Quote_Requested__c)= 'Unknown'
			|| TEXT(eq_Quote_Requested__c)= ''
			  ) 
		   && (TEXT(Buying_Horizon__c)= '6-12 Months'
			|| TEXT(Buying_Horizon__c)= '12+ Months'
			  )
		  )
		   , 'B - Prospect'

				  , IF(
					   (
						   (TEXT(eq_Default_MQL__c)= 'false'
						 || TEXT(eq_Default_MQL__c)= 'Unknown'
						 || TEXT(eq_Default_MQL__c)= ''
							)
						 && (TEXT(eq_Contact_Requested__c)= 'false'
						 ||  TEXT(eq_Contact_Requested__c)= 'Unknown'
						 ||  TEXT(eq_Contact_Requested__c)= ''
							)
						 && (TEXT(eq_Quote_Requested__c)= 'false'
						 || TEXT(eq_Quote_Requested__c)= 'Unknown'
						 || TEXT(eq_Quote_Requested__c)= ''
							)
						 && (TEXT(Buying_Horizon__c)= 'Not Asked'
						 || TEXT(Buying_Horizon__c)= 'No Plans'
						 || TEXT(Buying_Horizon__c)= ''
							)
						)							   
					   , 'C - Suspect'
					   , ''
					  ) 
		  ) 
			)
		, ''
  )
/* TEST Data with:*/
/*SELECT Id,fxEvaluateRatingCritera__c,Rating, eq_Default_MQL__c,eq_Contact_Requested__c,eq_Quote_Requested__c,Buying_Horizon__c,LeadSource,Contact_Requested__c FROM Lead where recordtype.developername = 'Informatics' LIMIT 1000 */
